// Edit the URL list below — one entry per competitor page to monitor.
// `countryCode` sets the ScraperAPI proxy region (us, gb, de, fr, etc.).

const targets = [
  { url: 'https://www.anthropic.com/news', countryCode: 'us' },
  { url: 'https://openai.com/blog', countryCode: 'us' },
  { url: 'https://blog.google/technology/ai/', countryCode: 'us' },
];

return targets.map((t, i) => ({
  json: t,
  pairedItem: { item: i },
}));

// Clean the markdown body, cap length to keep AI cost predictable,
// and compute a stable hash of the content.

const item = $input.first().json;
const response = item && item.response;
const body = (response && response.body) || '';

const cleaned = String(body)
  .replace(/\u0000/g, '')
  .replace(/\r\n/g, '\n')
  .replace(/\n{3,}/g, '\n\n')
  .trim();

const MAX = 8000;
const content = cleaned.length > MAX ? cleaned.slice(0, MAX) + '\n…(truncated)' : cleaned;

// FNV-1a 32-bit hash — fast, dependency-free, plenty for change detection.
let h = 2166136261;
for (let i = 0; i < content.length; i++) {
  h ^= content.charCodeAt(i);
  h = Math.imul(h, 16777619);
}
const hash = (h >>> 0).toString(16);

const url = $('Batch Process URLs').item.json.url;

return [{
  json: {
    url,
    content,
    hash,
    scraped_at: new Date().toISOString(),
    fetch_error: response && response.statusCode && response.statusCode >= 400 ? `HTTP ${response.statusCode}` : '',
  },
  pairedItem: { item: 0 },
}];

// Combine the current scrape with whatever Lookup Previous returned.
// First-time URLs have no previous row — treat that as a meaningful change
// so the AI can summarise the initial baseline.

const current = $('Clean and Cap Content').first().json;
const previous = $input.first().json || {};

const hasPrevious = !!previous.last_content_hash;
const hashChanged = !hasPrevious || previous.last_content_hash !== current.hash;
const significant = current.content && current.content.length > 200; // skip near-empty pages

return [{
  json: {
    url: current.url,
    current_content: current.content,
    current_hash: current.hash,
    current_seen_at: current.scraped_at,
    previous_content: hasPrevious ? (previous.last_content || '') : '',
    previous_hash: hasPrevious ? previous.last_content_hash : '',
    previous_seen_at: hasPrevious ? (previous.last_seen_at || 'unknown') : 'never',
    first_seen: !hasPrevious,
    changed: hashChanged && significant,
  },
  pairedItem: { item: 0 },
}];

