parameters.jsCode:
const changes = (($input.first().json || {}).changes || [])
  .filter(c => c.last_summary && c.last_summary !== 'NO_MATERIAL_CHANGE');

const esc = (s) => String(s == null ? '' : s).replace(/[&<>"']/g, c => ({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]));

const today = new Date().toISOString().slice(0, 10);
const subject = `Competitor content update — ${changes.length} change${changes.length === 1 ? '' : 's'} on ${today}`;

const cardsHtml = changes.map(c => `<div style="border-left:3px solid #4a90e2;padding:8px 12px;margin:0 0 14px;">
  <div style="font-weight:600;margin-bottom:4px;"><a href="${esc(c.url)}" style="color:#1f6fcc;text-decoration:none;">${esc(c.url)}</a></div>
  <div style="color:#333;font-size:14px;">${esc(c.last_summary)}</div>
</div>`).join('');

const html = `<div style="font-family:-apple-system,Segoe UI,sans-serif;max-width:680px;">
  <h2 style="margin:0 0 12px;">${esc(subject)}</h2>
  <p style="color:#555;margin:0 0 16px;">Pages monitored via ScraperAPI. Summaries written by AI on detected changes.</p>
  ${cardsHtml}
</div>`;

const slackBlocks = JSON.stringify({
  blocks: [
    { type: 'header', text: { type: 'plain_text', text: subject } },
    ...changes.flatMap(c => ([
      { type: 'section', text: { type: 'mrkdwn', text: `*<${c.url}|${c.url}>*\n${c.last_summary}` } },
      { type: 'divider' },
    ])),
  ],
});

const text = changes.map(c => `• ${c.url}\n  ${c.last_summary}`).join('\n\n');

return [{ json: { count: changes.length, subject, html, text, slackBlocks } }];
